import React, { useState } from "react";
import styled from "styled-components";
import { Link, useHistory } from "react-router-dom";
import { Icons, Images, mainPageIcons } from "../../assets/Resources";
import { message } from "antd";
import { authService } from "../../firebase";

const Container = styled.div`
  width: 100%;
  height: 100vh;
  position: relative;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  z-index: 1;
`;

const BackgroundImg = styled.div`
  width: 100%;
  height: 100%;
  background-repeat: no-repeat;
  background-position: center;
  background-image: url(${Images.Background3});
  background-size: cover;
  position: absolute;
  z-index: -2;
`;
const BackgroundFilter = styled.div`
  width: 100%;
  height: 100%;
  position: absolute;
  background-color: rgba(0, 0, 0, 50%);
  z-index: -1;
`;
const Button = styled.div`
  border: 2px solid white;
  padding: 10px 20px;
  width: 42%;
  margin: 10px 0;
  text-align: center;
  font-family: Arial;
  font-size: 18px;
  font-weight: bold;
  font-stretch: normal;
  font-style: normal;
  line-height: 1.15;
  letter-spacing: normal;
  color: #ffffff;
  cursor: pointer;
  @media (max-width: 430px) {
    font-size: 14px;
    padding: 10px 30px;
  }
`;
const InputBox = styled.input`
  width: 45%;
  margin: 15px;
  background-color: rgba(0, 0, 0, 0);
  border: none;
  border-bottom: 2px solid white;
  padding: 10px;
  color: white;
  outline: none;
  font-size: 15px;
  ::placeholder {
    color: white;
  }
  @media (max-width: 430px) {
    width: 52%;
  }
`;
const Img = styled.img`
  width: 15%;
  margin-bottom: 50px;
  @media (max-width: 430px) {
    font-size: 12px;
    padding-top: 30px;
    margin: 30px 0px;
  }
`;
const ImgNav = styled.img`
  width: 7%;
  margin-bottom: 50px;
`;
const NavWrapper = styled.div`
  position: absolute;
  top: 0;
  padding: 20px;
  width: 90%;
  display: flex;
  justify-content: space-between;
`;
const TextBox = styled.div`
  width: 30%;
  display: flex;
  justify-content: space-between;
`;
const NavText = styled.div`
  font-family: NanumGothic;
  padding: 10px;
  font-size: 32px;
  font-weight: 800;
  font-stretch: normal;
  font-style: normal;
  line-height: 1.13;
  letter-spacing: normal;
  text-align: center;
  color: #ffffff;
  @media (max-width: 430px) {
    font-size: 20px;
    padding: 3px;
  }
`;
const Text = styled.div`
  font-family: NanumGothic;
  font-size: 14px;
  font-weight: normal;
  font-stretch: normal;
  font-style: normal;
  line-height: 1.7;
  letter-spacing: normal;
  text-align: left;
  color: #ffffff;
  @media (max-width: 430px) {
    font-size: 10px;
  }
`;

const Login = () => {
  const history = useHistory();
  const [id, setId] = useState("");
  const [pw, setPw] = useState("");
  return (
    <Container>
      <BackgroundImg />
      <BackgroundFilter />
      <NavWrapper>
        <ImgNav src={Icons.menu} />
        <NavText>융특 커뮤니티 슝</NavText>
        <ImgNav src={Icons.화살표} />
      </NavWrapper>
      <Img src={mainPageIcons.profile} />
      <InputBox
        type="id"
        placeholder="아이디"
        value={id}
        disabled={false}
        onChange={({ target: { value } }) => setId(value)}
      />
      <InputBox
        type="password"
        placeholder="비밀번호"
        value={pw}
        onChange={({ target: { value } }) => setPw(value)}
      />
      <Button
        onClick={async () => {
          if (id === "" || pw === "") {
            message.error("아이디와 비밀번호를 입력해주세요.");
            return;
          }
          await authService.signInWithEmailAndPassword(id, pw).catch(() => {
            message.error("아이디 혹은 비밀번호가 일치하지 않습니다.");
          });
          const idToken = await authService.currentUser
            .getIdToken()
            .catch((err) => {
              message.error("토큰 실패. 개발자에게 문의해주세요.");
            });
          localStorage.setItem("idToken", idToken);
          message.success("로그인 성공");
        }}>
        로그인
      </Button>
      <Button>Google in with ⚽</Button>
      <TextBox>
        <Text onClick={() => history.push("/signup")}>회원가입</Text>
        <Text onClick={() => history.push("/login/lostpw")}>ID/PW찾기</Text>
      </TextBox>
    </Container>
  );
};
export default Login;
